/**
 * Notification service — handles sending notifications in response to events.
 *
 * ARCHITECTURE: Event-driven with adapter pattern.
 *
 * All notifications flow through this service:
 * 1. Domain events arrive via EventBus subscriptions (e.g., order:created)
 * 2. This service builds a NotificationPayload from the event
 * 3. The payload is dispatched to the appropriate NotificationAdapter by channel
 * 4. Results are logged and notification:sent / notification:failed events emitted
 *
 * CONSTRAINTS:
 * - All event triggers MUST go through EventBus.emit() — no direct calls or callbacks
 * - All delivery channels MUST implement NotificationAdapter interface
 * - Adapters are registered via registerAdapter() — one adapter per channel
 * - The service never throws on delivery failure; it emits notification:failed instead
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and emitting notification events
 * - NotificationAdapter implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationChannel,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * One adapter per channel — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Send a notification through the appropriate adapter.
   * If no adapter is registered for the channel, the notification is stored
   * with status 'failed' and a notification:failed event is emitted.
   */
  async send(payload: NotificationPayload): Promise<Notification> {
    const adapter = this.adapters.get(payload.channel);

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      type: payload.type,
      channel: payload.channel,
      subject: payload.subject,
      body: payload.body,
      status: 'pending',
      metadata: payload.metadata,
      sentAt: new Date(),
    };

    if (!adapter) {
      notification.status = 'failed';
      this.notifications.push(notification);
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);

      await this.eventBus.emit({
        type: 'notification:failed',
        recipient: payload.recipient,
        channel: payload.channel,
        error: `No adapter registered for channel: ${payload.channel}`,
        timestamp: new Date(),
      });

      return notification;
    }

    const result = await adapter.send(payload);

    notification.status = result.success ? 'sent' : 'failed';
    this.notifications.push(notification);

    if (result.success) {
      this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);
      await this.eventBus.emit({
        type: 'notification:sent',
        notification,
        timestamp: new Date(),
      });
    } else {
      this.logger.warn(`Notification failed: ${notification.id} — ${result.error}`);
      await this.eventBus.emit({
        type: 'notification:failed',
        recipient: payload.recipient,
        channel: payload.channel,
        error: result.error ?? 'Unknown error',
        timestamp: new Date(),
      });
    }

    return notification;
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * All event subscriptions are centralized here — the single source of truth
   * for what events produce notifications.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: event.user.email,
      type: 'order-confirmation',
      channel: 'email',
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      status: 'sent',
      sentAt: new Date(),
    };

    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${event.user.email}`);
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: event.order.userId,
      type: 'order-status-update',
      channel: 'email',
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      status: 'sent',
      sentAt: new Date(),
    };

    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${event.order.userId}`);
  }
}

